import{_ as i,o as a,c as s,a0 as t}from"./chunks/framework.CEW4uG-d.js";const u=JSON.parse('{"title":"Pricing & License Keys","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pricing.md","filePath":"guide/pricing.md"}'),r={name:"guide/pricing.md"};function n(o,e,l,c,h,d){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="pricing-license-keys" tabindex="-1">Pricing &amp; License Keys <a class="header-anchor" href="#pricing-license-keys" aria-label="Permalink to &quot;Pricing &amp; License Keys&quot;">​</a></h1><p>BlockGuard CLI is a premium, subscription-based service. We keep our rates highly affordable so that everyone can protect their digital privacy.</p><h2 id="pricing-plans" tabindex="-1">Pricing Plans <a class="header-anchor" href="#pricing-plans" aria-label="Permalink to &quot;Pricing Plans&quot;">​</a></h2><ul><li><strong>Monthly Subscription:</strong> <strong>$2 USD per month</strong></li><li><strong>Trial Key:</strong> <strong>Free for 3 Days</strong> (Try before you buy!)</li></ul><p>We offer flexible billing periods (Quarterly, Half-yearly, and Yearly) with discounts.</p><hr><h2 id="🎁-how-to-get-a-free-trial-key" tabindex="-1">🎁 How to get a Free Trial Key <a class="header-anchor" href="#🎁-how-to-get-a-free-trial-key" aria-label="Permalink to &quot;🎁 How to get a Free Trial Key&quot;">​</a></h2><p>To get your free 3-day trial key, simply send us a message on Signal:</p><p align="center"><a href="https://signal.me/#eu/5hn89XV1PsUQlPRc0WhEoUEh197WioxzFJj-CTXOGe1Boymy0-FCub3zwWXa_L3a" target="_blank"><img src="https://img.shields.io/badge/Signal-Message%20Us%20For%20Key-3a76f0?style=for-the-badge&amp;logo=signal&amp;logoColor=white" alt="Contact on Signal"></a></p><p>State that you want to request a <strong>3-day trial key for BlockGuard CLI</strong>. We will generate and send you a trial key instantly with absolutely no commitment or payment info required!</p><hr><h2 id="🔑-activating-your-key" tabindex="-1">🔑 Activating your Key <a class="header-anchor" href="#🔑-activating-your-key" aria-label="Permalink to &quot;🔑 Activating your Key&quot;">​</a></h2><p>Once you receive your key, activate it via the command line.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Always run the activation command with <strong><code>sudo</code></strong> (Linux/macOS) or as <strong>Administrator</strong> (Windows). This ensures the license is registered for the root user, which is required because BlockGuard binds to system-level privileged port 53.</p></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> activate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR-LICENSE-KEY</span></span></code></pre></div><p>If successful, you will see your plan type, subscriber email, and subscription expiration date.</p><hr><h2 id="🔒-device-limits-hardware-hwid" tabindex="-1">🔒 Device Limits &amp; Hardware HWID <a class="header-anchor" href="#🔒-device-limits-hardware-hwid" aria-label="Permalink to &quot;🔒 Device Limits &amp; Hardware HWID&quot;">​</a></h2><p>To prevent license sharing, each key has a device limit.</p><ul><li>During activation, BlockGuard registers your device&#39;s unique <strong>Hardware ID (HWID)</strong>.</li><li>If you reach the device limit, you can deactivate any unused machines by running:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset-license</span></span></code></pre></div>This will immediately free up the slot on your subscription key.</li></ul>',20)])])}const g=i(r,[["render",n]]);export{u as __pageData,g as default};
